// Filter: only leads in the 4–12 day follow-up window.
// email_sent_at between 4 and 12 days ago = contacted recently but not too long ago.
// Also: open_count 1–3 (opened but haven't clicked through obsessively).
// Also: last_opened_at > 1 day ago (not actively reading right now).
// Also: must have email_address.

const item = $input.item.json;

if (!item.email_address) return [{ json: { _skip: true } }];
if (!item.email_sent_at) return [{ json: { _skip: true } }];

const now = Date.now();
const sentAt = new Date(item.email_sent_at).getTime();
const daysSinceSent = (now - sentAt) / (1000 * 60 * 60 * 24);

const lastOpenedAt = item.last_opened_at ? new Date(item.last_opened_at).getTime() : 0;
const daysSinceOpen = lastOpenedAt ? (now - lastOpenedAt) / (1000 * 60 * 60 * 24) : 999;

// Follow-up window: sent 4–12 days ago
if (daysSinceSent < 4 || daysSinceSent > 12) return [{ json: { _skip: true } }];

// Not actively reading right now (opened more than 1 day ago)
if (daysSinceOpen < 1) return [{ json: { _skip: true } }];

// Not clicking obsessively (if click_count > 0, they're engaged — let them act)
if (item.click_count > 0) return [{ json: { _skip: true } }];

const business = item.business_name || 'your business';
const city = [item.location_city, item.location_state].filter(Boolean).join(', ');
const cityLine = city ? ` in ${city}` : '';

const subject = `Still thinking it over? — ${business}`;

const body_html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="background:#ffffff;color:#1a1a1a;font-family:Arial,sans-serif;margin:0;padding:0;">
  <div style="max-width:560px;margin:0 auto;padding:32px 24px;">
    <p style="font-size:15px;line-height:1.6;margin:0 0 16px;">Hi there,</p>
    <p style="font-size:15px;line-height:1.6;margin:0 0 16px;">
      I noticed you had a chance to look at our analysis for <strong>${business}</strong>${cityLine} — just wanted to follow up and see if you had any questions.
    </p>
    <p style="font-size:15px;line-height:1.6;margin:0 0 16px;">
      We identified a few specific improvements that could help <strong>${business}</strong> appear more often in AI search results (ChatGPT, Google AI Overviews, Perplexity). Happy to walk you through them in a quick call.
    </p>
    <div style="margin:28px 0;">
      <a href="https://nrankai.com/book" style="background:#4f46e5;color:#ffffff;text-decoration:none;padding:12px 28px;border-radius:6px;font-size:14px;font-weight:600;display:inline-block;">Book a 15-min call</a>
    </div>
    <p style="font-size:13px;color:#666;line-height:1.6;margin:0 0 8px;">Or just reply to this email — happy to answer any questions directly.</p>
    <hr style="border:none;border-top:1px solid #eee;margin:24px 0;">
    <p style="font-size:12px;color:#999;margin:0;">
      nrankai.com · <a href="https://api.nrankai.com/unsubscribe?email=${encodeURIComponent(item.email_address)}" style="color:#999;">Unsubscribe</a>
    </p>
  </div>
</body>
</html>`;

return [{ json: { ...item, _skip: false, subject, body_html } }];
